import React from 'react';
import { Link } from 'react-router-dom';
import SEOHead from './SEOHead';
import shopConfig from '../shop.config';

function Delivery() {
    return (
        <div className="min-h-screen bg-[#FDFBF7]">
            <SEOHead
                title={`Доставка дров у Києві та області – ${shopConfig.name}`}
                description="Швидка доставка колотих дров по Києву та Київській області. Власний автопарк вантажівок, чесний об'єм."
                ogImage="/og-delivery.jpg"
            />

            {/* Hero Banner */}
            <div className="relative overflow-hidden py-16 md:py-24 text-center">
                <div className="relative z-10 container mx-auto px-6">
                    <div className="text-xs font-bold uppercase tracking-[0.3em] text-[#2d5a27] mb-4">{shopConfig.name}</div>
                    <h1 className="text-4xl md:text-6xl font-black text-gray-900 uppercase tracking-tight mb-4"
                        style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>
                        Доставка дров
                    </h1>
                    <div className="w-20 h-1 bg-[#2d5a27] mx-auto mb-6 rounded-full" />
                    <p className="text-gray-500 text-lg max-w-xl mx-auto">
                        Оперативна доставка власного автотранспортом. Чесний об'єм та гарантія якості.
                    </p>
                </div>
            </div>

            {/* Delivery Options Cards */}
            <div className="container mx-auto px-6 pb-16">
                <div className="max-w-5xl mx-auto">

                    {/* 3 Method Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-5 md:gap-6 mb-16">
                        {[
                            {
                                icon: '🚚',
                                title: "Власним автотранспортом",
                                desc: 'Газель (до 6 складометрів)',
                                price: 'від 600 грн',
                                sub: 'Залежить від кілометражу',
                                priceColor: '#2d5a27',
                                highlight: true
                            },
                            {
                                icon: '🚛',
                                title: 'Великі об\'єми',
                                desc: 'ЗІЛ, Камаз (до 15 складометрів)',
                                price: 'від 1200 грн',
                                sub: 'Оптимально для великих замовлень',
                                priceColor: '#e67e22',
                                highlight: false
                            },
                            {
                                icon: '🏪',
                                title: 'Самовивіз',
                                desc: 'З нашого складу в Києві',
                                price: 'Безкоштовно',
                                sub: shopConfig.contact.address,
                                priceColor: '#22c55e',
                                highlight: false
                            }
                        ].map((item, i) => (
                            <div key={i} className={`relative group bg-white rounded-2xl md:rounded-3xl p-8 text-center transition-all duration-300 hover:-translate-y-1 border shadow-[0_4px_20px_rgba(0,0,0,0.06)] hover:shadow-[0_8px_30px_rgba(0,0,0,0.1)] ${item.highlight
                                ? 'border-[#2d5a27]/40'
                                : 'border-gray-100'
                                }`}>
                                {item.highlight && (
                                    <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-4 py-1 bg-[#2d5a27] text-white text-xs font-black uppercase tracking-widest rounded-full shadow-sm">
                                        Популярно
                                    </div>
                                )}
                                <div className="text-5xl mb-5">{item.icon}</div>
                                <h3 className="text-xl font-black text-gray-900 mb-3 uppercase"
                                    style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>{item.title}</h3>
                                <p className="text-gray-500 mb-5 text-sm">{item.desc}</p>
                                <div className="text-2xl font-black mb-2" style={{ color: item.priceColor }}>{item.price}</div>
                                <p className="text-xs text-gray-500">{item.sub}</p>
                            </div>
                        ))}
                    </div>

                    {/* Important Info */}
                    <div className="bg-white rounded-2xl md:rounded-3xl p-8 md:p-12 mb-12 border border-gray-100 shadow-[0_4px_20px_rgba(0,0,0,0.06)]">
                        <h2 className="text-2xl font-black text-gray-900 mb-8 uppercase flex items-center gap-3"
                            style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>
                            <span className="w-8 h-1 bg-[#2d5a27] rounded-full inline-block" />
                            Особливості доставки
                        </h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            {[
                                { icon: '⏰', title: 'Час доставки', text: 'Зазвичай доставка здійснюється на наступний день після замовлення, або в день замовлення за наявності вільних машин.' },
                                { icon: '📦', title: 'Об\'єм постачання', text: 'Дрова доставляються щільно укладеними в кузові (складометрами), що дозволяє вам легко перевірити замовлений об\'єм перед вивантаженням.' },
                                { icon: '💪', title: 'Вивантаження', text: 'Базова вартість доставки включає лише вивантаження поруч з машиною. Перенесення дров та складання в дровітню оплачується окремо та обговорюється заздалегідь.' },
                                { icon: '💳', title: 'Оплата', text: "Оплата здійснюється по факту доставки готівкою водію, після перевірки об'єму та якості дров. Можливий переказ на карту." }
                            ].map((item, i) => (
                                <div key={i} className="flex gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-[#F0FDF4] flex items-center justify-center text-2xl flex-shrink-0">
                                        {item.icon}
                                    </div>
                                    <div>
                                        <h4 className="font-black text-gray-900 mb-1.5 uppercase text-sm tracking-wide"
                                            style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>{item.title}</h4>
                                        <p className="text-gray-500 text-sm leading-relaxed">{item.text}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Delivery Zones Table */}
                    <div className="mb-14">
                        <h2 className="text-2xl font-black text-gray-900 text-center uppercase mb-8"
                            style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>
                            Орієнтовні зони та вартість (Газель)
                        </h2>
                        <div className="overflow-x-auto bg-white rounded-2xl md:rounded-3xl border border-gray-100 shadow-[0_4px_20px_rgba(0,0,0,0.06)]">
                            <table className="w-full">
                                <thead>
                                    <tr className="border-b border-gray-100">
                                        <th className="px-8 py-5 text-left font-black text-xs uppercase tracking-widest text-[#2d5a27]">Зона</th>
                                        <th className="px-8 py-5 text-left font-black text-xs uppercase tracking-widest text-[#2d5a27]">Вартість доставки</th>
                                        <th className="px-8 py-5 text-left font-black text-xs uppercase tracking-widest text-[#2d5a27]">Райони/Населені пункти</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {[
                                        { zone: 'Київ (Правий берег)', price: 'від 600 грн', time: 'Голосіївський, Печерський, Святошинський, Солом\'янський, Шевченківський, Оболонський, Подільський' },
                                        { zone: 'Київ (Лівий берег)', price: 'від 700 грн', time: 'Дарницький, Деснянський, Дніпровський' },
                                        { zone: 'Передмістя (до 15 км)', price: 'від 900 грн', time: 'Вишневе, Крюківщина, Боярка, Ірпінь, Буча, Вишгород, Бровари' },
                                        { zone: 'Область (до 40 км)', price: 'від 1500 грн', time: 'Обухів, Васильків, Бориспіль, Макарів' }
                                    ].map((row, i) => (
                                        <tr key={i} className="group transition-colors hover:bg-[#F0FDF4]/50 border-b border-gray-50 last:border-0">
                                            <td className="px-8 py-5 text-gray-900 font-medium whitespace-nowrap">{row.zone}</td>
                                            <td className="px-8 py-5 font-black text-[#e67e22] whitespace-nowrap">{row.price}</td>
                                            <td className="px-8 py-5 text-gray-500">{row.time}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                        <p className="text-sm text-gray-400 mt-4 text-center">
                            * Остаточна вартість доставки розраховується індивідуально диспетчером при підтвердженні замовлення і залежить від точної відстані до об'єкту.
                        </p>
                    </div>

                    {/* Contact CTA */}
                    <div className="rounded-2xl md:rounded-3xl p-10 md:p-14 text-center relative overflow-hidden bg-[#2d5a27]">
                        <div className="relative z-10">
                            <h2 className="text-3xl md:text-5xl font-black text-white uppercase mb-4"
                                style={{ fontFamily: "'Oswald', 'Oswald Fallback', sans-serif" }}>
                                Розрахувати точну вартість?
                            </h2>
                            <p className="text-white/70 text-lg mb-8">
                                Зателефонуйте нам або залиште заявку, і ми розрахуємо ціну дров з урахуванням доставки до вашого будинку
                            </p>
                            <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
                                <a href={`tel:${shopConfig.contact.phone.replace(/\D/g, '')}`}
                                    className="flex items-center gap-2 text-xl font-black text-[#e67e22] hover:text-white transition-colors">
                                    📞 {shopConfig.contact.phone}
                                </a>
                                <span className="text-white/30 hidden sm:block">|</span>
                                <Link
                                    to="/catalog/"
                                    className="inline-block px-10 py-4 bg-[#e67e22] hover:bg-[#d35400] text-white font-black text-sm uppercase tracking-widest rounded-full transition-all hover:scale-105 shadow-md"
                                >
                                    Перейти в каталог
                                </Link>
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}

export default Delivery;
